#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        long long N; scanf("%lld",&N);
        __int128 ans = (__int128)14 * N + 6;
        long long out = (long long)ans;
        printf("%lld\n", out);
    }
    return 0;
}

